const body = $input.first().json.body || $input.first().json;
// This is an analyst validation submission
return [{ json: {
  finding_id: body.finding_id,
  validation_status: body.validation_status,
  analyst_notes: body.analyst_notes || '',
  updated_severity: body.updated_severity || null,
  analyst_id: body.analyst_id || 'unknown'
} }];

const findings = $input.all().map(i => i.json);
const immediate = findings.filter(f => f.priority_bucket === 'immediate_attention');
const high = findings.filter(f => f.priority_bucket === 'high_priority');
const medium = findings.filter(f => f.priority_bucket === 'medium_priority');
const other = findings.filter(f => !['immediate_attention','high_priority','medium_priority'].includes(f.priority_bucket));

const N8N_URL = 'https://outstanding-blessing-production-1d4b.up.railway.app';

const formatFinding = f =>
  `• [${f.severity?.toUpperCase()}] ${f.title}\n  Asset: ${f.asset_value} | Client: ${f.client_name}\n  Score: ${f.recon_score} | Validate: POST ${N8N_URL}/webhook/recon-os/findings/validate\n  Body: {"finding_id":"${f.id}","validation_status":"validated","analyst_notes":"..."}`;

const digest = [
  `RECON OS — Daily Analyst Queue`,
  `Date: ${new Date().toISOString().split('T')[0]}`,
  `Total pending: ${findings.length} findings`,
  '',
  immediate.length > 0 ? `🔴 IMMEDIATE ATTENTION (${immediate.length}):\n${immediate.slice(0,5).map(formatFinding).join('\n')}` : '',
  high.length > 0 ? `🟠 HIGH PRIORITY (${high.length}):\n${high.slice(0,5).map(formatFinding).join('\n')}` : '',
  medium.length > 0 ? `🟡 MEDIUM PRIORITY (${medium.length})` : '',
  other.length > 0 ? `⚪ OTHER (${other.length})` : '',
  '',
  `Validation options: validated | analyst_reviewed | likely_false_positive`
].filter(Boolean).join('\n');

return [{ json: { digest, finding_count: findings.length, immediate_count: immediate.length } }];
